// // This is a negative-edge-triggered D flip-flop that captures the value of input D on the falling edge of the CLK and holds that value at output Q until the next falling edge.
module top_module(
    input D,
    input CLK,
    output reg Q  // Change to reg to hold state
);wire GATE_N;

    assign GATE_N = ~CLK;

    always @(posedge CLK) begin
        Q <= D;  // Use a simple always block to implement the D flip-flop
    end

endmodule
